import { Router } from 'express';
import { createMember, deleteMember, getMemberById, listMembers, updateMember, } from '../controllers/member.controller.js';
import { authenticate } from '../middleware/auth.middleware.js';
import { authorize } from '../middleware/authorize.middleware.js';
import { upload } from '../middleware/upload.middleware.js';
import { validateRequest } from '../middleware/validate.middleware.js';
import { createMemberValidator, listMembersValidator, memberIdValidator, updateMemberValidator, } from '../validators/member.validator.js';
export const memberRouter = Router();
memberRouter.get('/', authenticate, listMembersValidator, validateRequest, listMembers);
memberRouter.post('/', authenticate, authorize('super_admin', 'admin', 'manager'), upload.single('profileImage'), createMemberValidator, validateRequest, createMember);
memberRouter.get('/:id', authenticate, memberIdValidator, validateRequest, getMemberById);
memberRouter.patch('/:id', authenticate, authorize('super_admin', 'admin', 'manager'), upload.single('profileImage'), updateMemberValidator, validateRequest, updateMember);
memberRouter.delete('/:id', authenticate, authorize('super_admin', 'admin'), memberIdValidator, validateRequest, deleteMember);
